-- ═══════════════════════════════════════
-- worldcup_characters 테이블 생성
-- ═══════════════════════════════════════

CREATE TABLE IF NOT EXISTS worldcup_characters (
  id           BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  category     TEXT NOT NULL CHECK (category IN ('protagonist', 'rival', 'female')),
  name_ko      TEXT NOT NULL,
  name_en      TEXT,
  work_ko      TEXT NOT NULL,
  work_en      TEXT,
  tagline_ko   TEXT,
  tagline_en   TEXT,
  quote_ko     TEXT,
  quote_en     TEXT,
  anilist_id   INTEGER,
  mal_id       INTEGER,
  override_image_url TEXT,
  popularity_tier TEXT NOT NULL DEFAULT 'B' CHECK (popularity_tier IN ('S', 'A', 'B')),
  archetype    TEXT,
  trait         TEXT,
  tone         TEXT,
  is_active    BOOLEAN NOT NULL DEFAULT TRUE,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- 인덱스
CREATE INDEX IF NOT EXISTS idx_wc_chars_active ON worldcup_characters (is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_wc_chars_category ON worldcup_characters (category);
CREATE INDEX IF NOT EXISTS idx_wc_chars_work ON worldcup_characters (work_ko);
CREATE INDEX IF NOT EXISTS idx_wc_chars_tier ON worldcup_characters (popularity_tier);

-- RLS 정책 (읽기 전용 공개)
ALTER TABLE worldcup_characters ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "worldcup_characters_read" ON worldcup_characters;
CREATE POLICY "worldcup_characters_read" ON worldcup_characters
  FOR SELECT USING (TRUE);

-- 세션 저장 테이블
CREATE TABLE IF NOT EXISTS worldcup_char_sessions (
  id           BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  session_key  TEXT NOT NULL,
  winner_id    BIGINT REFERENCES worldcup_characters(id),
  winner       TEXT NOT NULL,
  top4         JSONB,
  top4_tags    JSONB,
  lang         TEXT DEFAULT 'ko',
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE worldcup_char_sessions ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "worldcup_char_sessions_insert" ON worldcup_char_sessions;
CREATE POLICY "worldcup_char_sessions_insert" ON worldcup_char_sessions
  FOR INSERT WITH CHECK (TRUE);
DROP POLICY IF EXISTS "worldcup_char_sessions_read" ON worldcup_char_sessions;
CREATE POLICY "worldcup_char_sessions_read" ON worldcup_char_sessions
  FOR SELECT USING (TRUE);


